import React, { useEffect, useRef, useState, useCallback } from 'react';

const ICE_SERVERS = { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }, { urls: 'stun:stun2.l.google.com:19302' }] };

export default function AudioCall({ socket, currentUser, callState, onEnd }) {
  const [muted, setMuted] = useState(false);
  const [duration, setDuration] = useState(0);
  const [status, setStatus] = useState(callState.type === 'outgoing' ? 'Calling...' : 'Incoming call');

  const pcRef = useRef(null);
  const localStreamRef = useRef(null);
  const remoteAudioRef = useRef(null);
  const timerRef = useRef(null);
  const endedRef = useRef(false);

  const avatarColor = (name) => {
    const colors = ['linear-gradient(135deg,#e8748a,#c9a96e)', 'linear-gradient(135deg,#f59e0b,#ef4444)', 'linear-gradient(135deg,#10b981,#3b82f6)'];
    return colors[(name?.charCodeAt(0) || 0) % colors.length];
  };

  const formatDuration = (s) => `${String(Math.floor(s / 60)).padStart(2, '0')}:${String(s % 60).padStart(2, '0')}`;

  const cleanup = useCallback((notify = true) => {
    if (endedRef.current) return;
    endedRef.current = true;
    clearInterval(timerRef.current);
    if (notify) socket.emit('call:end', { to: callState.peer });
    if (pcRef.current) { try { pcRef.current.close(); } catch {} pcRef.current = null; }
    if (localStreamRef.current) { localStreamRef.current.getTracks().forEach(t => t.stop()); localStreamRef.current = null; }
    onEnd();
  }, []);

  const getMic = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
    localStreamRef.current = stream;
    return stream;
  };

  const buildPC = (stream) => {
    const pc = new RTCPeerConnection(ICE_SERVERS);
    pcRef.current = pc;
    stream.getTracks().forEach(t => pc.addTrack(t, stream));

    pc.ontrack = (e) => {
      if (remoteAudioRef.current && e.streams[0]) {
        remoteAudioRef.current.srcObject = e.streams[0];
        remoteAudioRef.current.play().catch(() => {});
      }
    };

    pc.onicecandidate = (e) => {
      if (e.candidate) socket.emit('call:ice', { to: callState.peer, candidate: e.candidate });
    };

    pc.onconnectionstatechange = () => {
      const s = pc.connectionState;
      if (s === 'connected') { setStatus('Connected'); timerRef.current = setInterval(() => setDuration(d => d + 1), 1000); }
      if (['disconnected', 'failed', 'closed'].includes(s)) cleanup(false);
    };

    return pc;
  };

  // Outgoing: get mic → build PC → create offer → send
  useEffect(() => {
    if (callState.type !== 'outgoing') return;
    (async () => {
      try {
        const stream = await getMic();
        const pc = buildPC(stream);
        const offer = await pc.createOffer({ offerToReceiveAudio: true });
        await pc.setLocalDescription(offer);
        socket.emit('call:offer', { to: callState.peer, from: currentUser.username, offer: pc.localDescription });
      } catch (err) {
        console.error('Outgoing call error:', err);
        setStatus('Mic error');
        setTimeout(() => cleanup(true), 2000);
      }
    })();
    return () => cleanup(false);
  }, []);

  // Socket events
  useEffect(() => {
    const onAnswer = async ({ answer }) => {
      try {
        if (pcRef.current && pcRef.current.signalingState !== 'closed') {
          await pcRef.current.setRemoteDescription(new RTCSessionDescription(answer));
        }
      } catch (e) { console.error('setRemoteDescription error:', e); }
    };

    const onIce = async ({ candidate }) => {
      try {
        if (pcRef.current && candidate && pcRef.current.remoteDescription) {
          await pcRef.current.addIceCandidate(new RTCIceCandidate(candidate));
        }
      } catch {}
    };

    const onEnded = () => {
      if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
      if (pcRef.current) { try { pcRef.current.close(); } catch {} }
      setStatus('Call ended');
      setTimeout(() => onEnd(), 800);
    };
    const onRejected = () => {
      if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
      if (pcRef.current) { try { pcRef.current.close(); } catch {} }
      setStatus('Call declined ❌');
      setTimeout(() => onEnd(), 1500);
    };
    const onBusy = () => {
      if (localStreamRef.current) localStreamRef.current.getTracks().forEach(t => t.stop());
      setStatus('User is busy 📵');
      setTimeout(() => onEnd(), 1500);
    };

    socket.on('call:answer', onAnswer);
    socket.on('call:ice', onIce);
    socket.on('call:ended', onEnded);
    socket.on('call:rejected', onRejected);
    socket.on('call:busy', onBusy);

    return () => {
      socket.off('call:answer', onAnswer);
      socket.off('call:ice', onIce);
      socket.off('call:ended', onEnded);
      socket.off('call:rejected', onRejected);
      socket.off('call:busy', onBusy);
    };
  }, []);

  const acceptCall = async () => {
    try {
      setStatus('Connecting...');
      const stream = await getMic();
      const pc = buildPC(stream);
      await pc.setRemoteDescription(new RTCSessionDescription(callState.offer));
      const answer = await pc.createAnswer();
      await pc.setLocalDescription(answer);
      socket.emit('call:answer', { to: callState.peer, answer: pc.localDescription });
    } catch (err) {
      console.error('Accept call error:', err);
      setStatus('Mic error');
      setTimeout(() => cleanup(true), 2000);
    }
  };

  const rejectCall = () => {
    socket.emit('call:reject', { to: callState.peer });
    endedRef.current = false;
    cleanup(false);
  };

  const toggleMute = () => {
    if (localStreamRef.current) {
      localStreamRef.current.getAudioTracks().forEach(t => { t.enabled = muted; });
      setMuted(m => !m);
    }
  };

  const isIncoming = callState.type === 'incoming' && status === 'Incoming call';
  const isActive = status === 'Connected';

  return (
    <div className="anim-fadeIn" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.88)', backdropFilter: 'blur(14px)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 3000 }}>
      <audio ref={remoteAudioRef} autoPlay playsInline />

      <div className="anim-scaleIn" style={{ background: 'linear-gradient(160deg,#2e1820,#1a0e14)', border: '1px solid #4e2830', borderRadius: 28, padding: '44px 36px', width: 300, textAlign: 'center', boxShadow: '0 32px 80px rgba(0,0,0,0.7)' }}>

        {/* Animated avatar */}
        <div style={{ position: 'relative', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', marginBottom: 22 }}>
          <div style={{ position: 'absolute', width: 110, height: 110, borderRadius: '50%', border: '2px solid rgba(232,116,138,0.25)', animation: 'statusRing 1.8s ease infinite' }} />
          <div style={{ position: 'absolute', width: 130, height: 130, borderRadius: '50%', border: '2px solid rgba(232,116,138,0.12)', animation: 'statusRing 1.8s ease 0.4s infinite' }} />
          <div style={{ width: 80, height: 80, borderRadius: '50%', background: avatarColor(callState.peer), display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 30, fontWeight: 700, color: '#fff', position: 'relative', zIndex: 1, boxShadow: '0 8px 24px rgba(232,116,138,0.3)' }}>
            {callState.peer[0].toUpperCase()}
          </div>
        </div>

        <div style={{ fontSize: 20, fontWeight: 700, color: '#f5e6e8', marginBottom: 6 }}>{callState.peer}</div>
        <div style={{ fontSize: 13, color: isActive ? '#4ade80' : '#c9a0a8', marginBottom: 36, letterSpacing: 0.3 }}>
          {isActive ? `🟢 ${formatDuration(duration)}` : status}
        </div>

        {isIncoming ? (
          <div style={{ display: 'flex', justifyContent: 'center', gap: 40 }}>
            <div style={{ textAlign: 'center' }}>
              <button onClick={rejectCall}
                style={{ width: 58, height: 58, borderRadius: '50%', background: 'rgba(248,113,113,0.15)', border: '2px solid rgba(248,113,113,0.4)', color: '#f87171', fontSize: 22, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'all 0.2s' }}
                onMouseEnter={e => { e.currentTarget.style.background='rgba(248,113,113,0.3)'; e.currentTarget.style.transform='scale(1.1)'; }}
                onMouseLeave={e => { e.currentTarget.style.background='rgba(248,113,113,0.15)'; e.currentTarget.style.transform='scale(1)'; }}
              >📵</button>
              <div style={{ fontSize: 11, color: '#f87171', fontWeight: 600 }}>Decline</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <button onClick={acceptCall}
                style={{ width: 58, height: 58, borderRadius: '50%', background: 'rgba(74,222,128,0.15)', border: '2px solid rgba(74,222,128,0.4)', color: '#4ade80', fontSize: 22, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'all 0.2s', animation: 'onlinePulse 1s ease infinite' }}
                onMouseEnter={e => { e.currentTarget.style.background='rgba(74,222,128,0.3)'; e.currentTarget.style.transform='scale(1.1)'; }}
                onMouseLeave={e => { e.currentTarget.style.background='rgba(74,222,128,0.15)'; e.currentTarget.style.transform='scale(1)'; }}
              >📞</button>
              <div style={{ fontSize: 11, color: '#4ade80', fontWeight: 600 }}>Accept</div>
            </div>
          </div>
        ) : (
          <div style={{ display: 'flex', justifyContent: 'center', gap: 28 }}>
            <div style={{ textAlign: 'center' }}>
              <button onClick={toggleMute}
                style={{ width: 52, height: 52, borderRadius: '50%', background: muted ? 'rgba(232,116,138,0.2)' : 'rgba(255,255,255,0.07)', border: `2px solid ${muted ? 'rgba(232,116,138,0.5)' : 'rgba(255,255,255,0.15)'}`, color: muted ? '#e8748a' : '#f5e6e8', fontSize: 20, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'all 0.2s' }}>
                {muted ? '🔇' : '🎙️'}
              </button>
              <div style={{ fontSize: 11, color: '#c9a0a8' }}>{muted ? 'Unmute' : 'Mute'}</div>
            </div>
            <div style={{ textAlign: 'center' }}>
              <button onClick={() => cleanup(true)}
                style={{ width: 52, height: 52, borderRadius: '50%', background: 'rgba(248,113,113,0.15)', border: '2px solid rgba(248,113,113,0.4)', color: '#f87171', fontSize: 20, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 8px', transition: 'all 0.2s' }}
                onMouseEnter={e => { e.currentTarget.style.background='rgba(248,113,113,0.3)'; e.currentTarget.style.transform='scale(1.1)'; }}
                onMouseLeave={e => { e.currentTarget.style.background='rgba(248,113,113,0.15)'; e.currentTarget.style.transform='scale(1)'; }}
              >📵</button>
              <div style={{ fontSize: 11, color: '#f87171' }}>End</div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
